#palindrome detection using a vanilla RNN with an embedding layer
#dataset generated by creating random palindromic strings 
import torch
import random
import torch.nn as nn 
import matplotlib.pyplot as plt

digits = "0123456789"

# generate a valid number string of given length
def generate_number(length):
    if length == 1:
        return random.choice(digits)
    else:
        first = random.choice("123456789")   # no leading zero
        rest = ''.join(random.choices(digits, k=length-1))
        return first + rest

# generate palindrome
def generate_palindrome(length):
    if length == 1:
        return random.choice(digits)

    half_length = length // 2

    # first digit cannot be zero if multi digit
    first_half = random.choice("123456789")
    if half_length > 1:
        first_half += ''.join(random.choices(digits, k=half_length-1))

    if length % 2 == 1:
        middle = random.choice(digits)
        palindrome = first_half + middle + first_half[::-1]
    else:
        palindrome = first_half + first_half[::-1]

    return palindrome

# generate non-palindrome
def generate_non_palindrome(length):
    # ensure length >= 2 (since length 1 is always palindrome)
    if length == 1:
        length = random.randint(2, 7)

    non_palindrome = generate_number(length)

    while non_palindrome == non_palindrome[::-1]:
        non_palindrome = generate_number(length)

    return non_palindrome

# build dataset
def build_dataset(num_examples):
    data = []

    half = num_examples // 2

    # positive examples
    for _ in range(half):
        length = random.randint(1, 7)
        num = generate_palindrome(length)
        data.append((num, 1))

    # negative examples
    for _ in range(half):
        length = random.randint(2, 7)  # avoid length 1
        num = generate_non_palindrome(length)
        data.append((num, 0))

    random.shuffle(data)
    return data

